kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet --eval '
rs.initiate({
  _id: "mongodb-replica",
  members: [
    { _id: 0, host: "mongodb-replica-0.mongodb-replica-svc.mongodb.svc.cluster.local:27017" },
    { _id: 1, host: "mongodb-replica-1.mongodb-replica-svc.mongodb.svc.cluster.local:27017" },
    { _id: 2, host: "mongodb-replica-2.mongodb-replica-svc.mongodb.svc.cluster.local:27017" }
  ]
})
'

kubectl exec -n mongodb mongodb-replica-0 -- mongosh --quiet --eval '
db.getSiblingDB("admin").createUser({
  user: "admin-user",
  pwd: "admin123password",
  roles: [
    { role: "root", db: "admin" }
  ]
});
print("admin-user created");
db.getSiblingDB("admin").createUser({
  user: "app-user",
  pwd: "app123password",
  roles: [
    { role: "readWrite", db: "appdb" }
  ]
});
print("app-user created");
'

kubectl exec -n mongodb mongodb-replica-0 -- mongosh \
  "mongodb://admin-user:admin123password@localhost:27017/admin?authSource=admin" \
  --quiet --eval '
db.getSiblingDB("admin").createUser({
  user: "app-user",
  pwd: "app123password",
  roles: [
    { role: "readWrite", db: "appdb" }
  ]
});
print("app-user created");
'

kubectl exec -n mongodb mongodb-replica-0 -- mongosh \
  "mongodb://app-user:app123password@localhost:27017/appdb?authSource=admin" \
  --quiet --eval '
db.testcol.insertOne({ msg: "hello from karma", ts: new Date().toISOString() });
const doc = db.testcol.findOne({ msg: "hello from karma" });
print("Read back:", JSON.stringify(doc));
db.testcol.drop();
print("Write/read verified.");
'

